730	
731	        for (i, lint) in lints.into_iter().enumerate() {
732	            for (j, suggestion) in lint.suggestions.into_iter().enumerate() {
733	                let mut text_chars: Vec<char> = text.chars().collect();
734	                suggestion.apply(lint.span, &mut text_chars);
735	                let suggestion_text: String = text_chars.into_iter().collect();
736	
737	                // Check for bad suggestions
