use crate::{
    Token,
    expr::{Expr, SequenceExpr},
    linting::{ExprLinter, Lint, LintKind, Suggestion, expr_linter::Chunk},
};

/// Detects when "flaunt" (to show off) is used where "flout" (to openly disregard rules) is intended.
pub struct FlauntFlout {
    expr: SequenceExpr,
}

impl Default for FlauntFlout {
    fn default() -> Self {
        Self {
            expr: SequenceExpr::any_capitalization_of("flaunt")
                .t_ws()
                .then_word_set(&[
                    "rule",
                    "rules",
                    "law",
                    "laws",
                    "regulation",
                    "regulations",
                    "ban",
                    "bans",
                    "prohibition",
                    "prohibitions",
                    "restriction",
                    "restrictions",
                    "policy",
                    "policies",
                    "order",
                    "orders",
                    "directive",
                    "directives",
                    "guideline",
                    "guidelines",
                    "decree",
                    "decrees",
                    "statute",
                    "statutes",
                    "edict",
                    "edicts",
                    "ruling",
                    "rulings",
                    "mandate",
                    "mandates",
                    "command",
                    "commands",
                    "convention",
                    "conventions",
                    "norm",
                    "norms",
                    "standard",
                    "standards",
                    "protocol",
                    "protocols",
                ]),
        }
    }
}

impl ExprLinter for FlauntFlout {
    type Unit = Chunk;

    fn expr(&self) -> &dyn Expr {
        &self.expr
    }

    fn match_to_lint(&self, toks: &[Token], src: &[char]) -> Option<Lint> {
        let verb_span = toks.first()?.span;
        let verb_chars = verb_span.get_content(src);

        enum Form {
            Base,
            Past,
            ThirdPerson,
            Ing,
        }

        let infl = match verb_chars
            .iter()
            .map(|c| c.to_ascii_lowercase())
            .collect::<Vec<_>>()
            .as_slice()
        {
            [.., 't'] => Form::Base,
            [.., 'd'] => Form::Past,
            [.., 's'] => Form::ThirdPerson,
            [.., 'g'] => Form::Ing,
            _ => return None,
        };

        Some(Lint {
            span: verb_span,
            lint_kind: LintKind::Malapropism,
            suggestions: vec![Suggestion::replace_with_match_case(
                match infl {
                    Form::Base => "flout",
                    Form::Past => "flouted",
                    Form::ThirdPerson => "flouts",
                    Form::Ing => "flouting",
                }
                .chars()
                .collect(),
                verb_chars,
            )],
            message: "`Flaunt` means to show off. Did you mean `flout`, which means to openly disregard a rule or law?".to_string(),
            ..Default::default()
        })
    }

    fn description(&self) -> &str {
        "Detects when `flaunt` (to show off) is used where `flout` (to openly disregard rules) is intended."
    }
}

#[cfg(test)]
mod tests {
    use super::FlauntFlout;
    use crate::linting::tests::assert_suggestion_result;

    #[test]
    fn fix_flaunt_rules() {
        assert_suggestion_result(
            "He flaunts the rules.",
            FlauntFlout::default(),
            "He flouts the rules.",
        );
    }

    #[test]
    fn fix_flaunted_laws() {
        assert_suggestion_result(
            "He flaunted US bankruptcy laws for personal gain.",
            FlauntFlout::default(),
            "He flouted US bankruptcy laws for personal gain.",
        );
    }

    #[test]
    fn fix_flaunting_laws() {
        assert_suggestion_result(
            "deranged scientists flaunting the laws of God and Man",
            FlauntFlout::default(),
            "deranged scientists flouting the laws of God and Man",
        );
    }

    #[test]
    fn fix_flaunt_rules_basic() {
        assert_suggestion_result(
            "some seem to flaunt the basic rules of punctuation",
            FlauntFlout::default(),
            "some seem to flout the basic rules of punctuation",
        );
    }

    #[test]
    fn fix_captain_who_flaunts_rules() {
        assert_suggestion_result(
            "a Kirk-esque captain who flaunts the rules",
            FlauntFlout::default(),
            "a Kirk-esque captain who flouts the rules",
        );
    }
}

